CREATE OR REPLACE FUNCTION public.can_user_post_status(chan_id uuid, usr_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  posting_setting text;
  user_role text;
  is_creator boolean;
BEGIN
  -- Get the channel setting and check if the user is the owner
  SELECT allow_status_posting_by, (creator_id = usr_id) 
  INTO posting_setting, is_creator
  FROM public.channels 
  WHERE id = chan_id;

  -- If the user is the channel creator, they can always post
  IF is_creator THEN
    RETURN true;
  END IF;

  -- If the setting is 'all', check if they are at least a member
  IF posting_setting = 'all' THEN
    RETURN EXISTS (
      SELECT 1 FROM public.channel_members 
      WHERE channel_id = chan_id AND user_id = usr_id
    );
  END IF;

  -- If setting is 'admin', check if their role is 'admin' or 'owner'
  IF posting_setting = 'admin' THEN
    SELECT role INTO user_role FROM public.channel_members 
    WHERE channel_id = chan_id AND user_id = usr_id;
    RETURN user_role IN ('admin', 'owner');
  END IF;

  RETURN false;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_private_inbox(target_user_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  new_thread_id UUID;
  existing_thread_id UUID;
BEGIN
  -- First check if it already exists
  SELECT id INTO existing_thread_id
  FROM inbox
  WHERE user_id = auth.uid()
    AND participant_id = target_user_id
    AND chat_type = 'private'
  LIMIT 1;

  IF existing_thread_id IS NOT NULL THEN
    RETURN existing_thread_id;
  END IF;

  -- Generate a new thread ID
  new_thread_id := gen_random_uuid();

  -- Insert for current user
  INSERT INTO inbox (id, user_id, participant_id, chat_type, unread_count)
  VALUES (new_thread_id, auth.uid(), target_user_id, 'private', 0);

  -- Insert for target user
  INSERT INTO inbox (id, user_id, participant_id, chat_type, unread_count)
  VALUES (new_thread_id, target_user_id, auth.uid(), 'private', 0);

  RETURN new_thread_id;
END;
$function$

