CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.sync_tag_counts()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF (TG_OP = 'INSERT') THEN
    -- Update post count
    UPDATE public.channel_posts SET tags_count = tags_count + 1 WHERE id = NEW.post_id;
    -- Update target channel count
    UPDATE public.channels SET tags_count = tags_count + 1 WHERE id = NEW.target_channel_id;
    RETURN NEW;
  ELSIF (TG_OP = 'DELETE') THEN
    UPDATE public.channel_posts SET tags_count = tags_count - 1 WHERE id = OLD.post_id;
    UPDATE public.channels SET tags_count = tags_count - 1 WHERE id = OLD.target_channel_id;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.toggle_channel_post_like(target_post_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  is_liked boolean;
  new_count int;
  target_channel_id uuid;
begin
  -- Check specifically in the channel_post_likes table
  select exists (
    select 1 from channel_post_likes 
    where user_id = auth.uid() and post_id = target_post_id
  ) into is_liked;

  if is_liked then
    delete from channel_post_likes where user_id = auth.uid() and post_id = target_post_id;
    new_count := -1;
  else
    insert into channel_post_likes (user_id, post_id) values (auth.uid(), target_post_id);
    new_count := 1;
  end if;

  update channel_posts set likes = coalesce(likes, 0) + new_count where id = target_post_id
  returning likes, channel_id into new_count, target_channel_id;

  if target_channel_id is not null then
    update channels set likes_count = coalesce(likes_count, 0) + (case when is_liked then -1 else 1 end) where id = target_channel_id;
  end if;

  return json_build_object('is_liked', not is_liked, 'new_likes', new_count);
end;
$function$

